}

resource "aws_route53_query_logging_config" "example" {
  hosted_zone_id = aws_route53_hosted_zone.primary.zone_id
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.route53.arn
}

resource "aws_iam_policy" "route53_query_logging_policy" {
  name        = "route53-query-logging-policy"
  description = "Policy for Route 53 query logging to CloudWatch Logs"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:aws_route53_example_com:*"
      },
    ]
  })
}

