  records = ["2.2.2.2"] # Replace with actual replica-1 instance IP
}

resource "aws_route53_record" "replica_2" {
  zone_id = aws_route53_hosted_zone.main.id
  name    = "replica-2"
  type    = "A"
  ttl     = 300
  records = ["3.3.3.3"] # Replace with actual replica-2 instance IP
}

resource "aws_route53_health_check" "primary_health_check" {
  name             = "primary-health-check"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  enable_sni       = true
  http_endpoint    = "http://primary" # Adjust endpoint as needed
  healthy_threshold = 2
}

resource "aws_route53_health_check" "replica_1_health_check" {
  name             = "replica-1-health-check"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  enable_sni       = true
  http_endpoint    = "http://replica-1" # Adjust endpoint as needed
  healthy_threshold = 2
}

resource "aws_route53_health_check" "replica_2_health_check" {
  name             = "replica-2-health-check"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  enable_sni       = true
  http_endpoint    = "http://replica-2" # Adjust endpoint as needed
  healthy_threshold = 2
}

resource "aws_route53_record" "weighted_routing" {
  zone_id = aws_route53_hosted_zone.main.id
  name    = "www.main" # Or your domain name
  type    = "A"
  ttl     = 60
  set_identifier = "weighted-set"

  weighted_routing_policy {
    weight = 50
    resource_record_set {
      name = "primary"
      type = "A"
      health_check_id = aws_route53_health_check.primary_health_check.id
    }
  }

  weighted_routing_policy {
    weight = 25
    resource_record_set {
      name = "replica-1"
      type = "A"
      health_check_id = aws_route53_health_check.replica_1_health_check.id
    }
  }

  weighted_routing_policy {
    weight = 25
    resource_record_set {
      name = "replica-2"
      type = "A"
      health_check_id = aws_route53_health_check.replica_2_health_check.id
    }
  }
}

