  name                      = "blue-asg"
  desired_capacity          = 1
  min_size                  = 1
  max_size                  = 1
  vpc_zone_identifier       = ["subnet-0bb1c79de3EXAMPLE"] # Replace with your subnet IDs
  launch_template {
    id      = aws_launch_template.blue.id
    version = "$Latest"
  }
}

resource "aws_autoscaling_group" "green" {
  name                      = "green-asg"
  desired_capacity          = 0
  min_size                  = 0
  max_size                  = 1
  vpc_zone_identifier       = ["subnet-0bb1c79de3EXAMPLE"] # Replace with your subnet IDs
  launch_template {
    id      = aws_launch_template.green.id
    version = "$Latest"
  }
}

resource "aws_route53_health_check" "blue_health_check" {
  name             = "blue-health-check"
  type             = "HTTP"
  request_path     = "/"
  fqdn             = "your_blue_elb_dns.elb.amazonaws.com" # Replace with your Blue ELB DNS
  port             = 80
  check_interval   = 30
  failure_threshold = 3
}

resource "aws_route53_health_check" "green_health_check" {
  name             = "green-health-check"
  type             = "HTTP"
  request_path     = "/"
  fqdn             = "your_green_elb_dns.elb.amazonaws.com" # Replace with your Green ELB DNS
  port             = 80
  check_interval   = 30
  failure_threshold = 3
}

resource "aws_route53_record" "blue" {
  zone_id = "your_zone_id" # Replace with your zone ID
  name    = "www.example.com" # Replace with your domain
  type    = "A"
  set_identifier = "blue"
  ttl     = 60
  records = ["your_blue_elb_ip"] # Replace with your Blue ELB IP
  health_check_id = aws_route53_health_check.blue_health_check.id
  routing_policy = "FAILOVER"
  failover_routing_policy {
    type = "PRIMARY"
  }
}

resource "aws_route53_record" "green" {
  zone_id = "your_zone_id" # Replace with your zone ID
  name    = "www.example.com" # Replace with your domain
  type    = "A"
  set_identifier = "green"
  ttl     = 60
  records = ["your_green_elb_ip"] # Replace with your Green ELB IP
  health_check_id = aws_route53_health_check.green_health_check.id
  routing_policy = "FAILOVER"
  failover_routing_policy {
    type = "SECONDARY"
  }
}
