resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild-policy"
  description = "Policy for CodeBuild"
  policy      = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:PutObject",
          "s3:PutObjectAcl"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:s3:::your-source-bucket/*"
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  description  = "An example CodeBuild project"

  source {
    type = "GITHUB"
    location = "https://github.com/your-repo/your-project.git"
  }

  environment {
    compute {
      type = "BUILD_GENERAL1_SMALL"
      image = "aws/codebuild/standard:5.0"
    }
    environment_variables = [
      {
        name  = "MY_VARIABLE"
        value = "my_value"
      }
    ]
  }

  artifacts {
    type = "ZIP"
    name = "output.zip"
    secondary_sources = [
      {
        name = "secondary-source"
        source = {
          type = "S3"
          bucket = "your-secondary-bucket"
          object = "path/to/secondary/artifact"
        }
      }
    ]
  }

  role_arn = aws_iam_role.codebuild_role.arn

}
