provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

data "aws_caller_identity" "current" {}

data "aws_ecr_image" "stable" {
  repository_name = "your-ecr-repository" # Replace with your ECR repository name
  image_tag      = "stable"
}

locals {
  image_tag = data.aws_ecr_image.stable.image_digest != null ? data.aws_ecr_image.stable.image_digest : data.aws_ecr_image.stable.image_tag
  aws_tags = {
    Environment = "dev"
    Terraform   = "true"
  }
  workspace_name = "my-eks-cluster"
}

