}

provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  client_certificate     = base64decode(module.eks.cluster_certificate)
  client_key             = module.eks.cluster_key
}

provider "helm" {
  kubernetes = {
    host                   = module.eks.cluster_endpoint
    client_certificate     = base64decode(module.eks.cluster_certificate)
    client_key             = module.eks.cluster_key
  }
}

