    cluster_name = "my-eks-cluster", # Replace with your EKS cluster name
    namespace    = "kube-system",
    deployment   = "coredns"
  }

  provisioner "local-exec" {
    command = <<EOT
      export KUBE_CONTEXT=arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/my-eks-cluster # Replace as needed
      kubectl --context ${KUBE_CONTEXT} -n kube-system patch deployment coredns -p '{"spec":{"template":{"spec":{"dnsPolicy":"ClusterFirst"}}}}

    EOT
  }

  depends_on = [aws_eks_fargate_profile.default]
