          Service = "eks-fargate-pods.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "fargate_pod_execution_policy" {
  role       = aws_iam_role.fargate_pod_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
}

resource "aws_eks_fargate_profile" "default" {
  cluster_name   = "my-eks-cluster" # Replace with your EKS cluster name
  fargate_profile_name = "my-fargate-profile"
  namespace      = "kube-system"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnets        = ["subnet-xxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyy"] # Replace with your subnet IDs - ensure cluster-association tag exists
}

resource "null_resource" "coredns_patch" {
  triggers = {
    cluster_name = "my-eks-cluster", # Replace with your EKS cluster name
    namespace    = "kube-system",
    deployment   = "coredns"
  }

  provisioner "local-exec" {
    command = <<EOT
      export KUBE_CONTEXT=arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/my-eks-cluster # Replace as needed
      kubectl --context ${KUBE_CONTEXT} -n kube-system patch deployment coredns -p '{"spec":{"template":{"spec":{"dnsPolicy":"ClusterFirst"}}}}

    EOT
  }

  depends_on = [aws_eks_fargate_profile.default]
}

data "aws_region" "current" {}
data "aws_caller_identity" "current" {}
