resource "aws_s3_bucket" "wellcomecollection_platform_infra" {
  bucket = "wellcomecollection-platform-infra"

  # Safeguard against accidental deletion
  versioning {
    enabled = true
  }

  # Set ACL to private
  acl    = "private"

  lifecycle_rule {
    id      = "tmp_prefix_lifecycle"
    prefix  = "tmp/"

    rule {
      expiration {
        days = 30
      }
    }
  }

  lifecycle_rule {
    id      = "versioning_lifecycle"
    enabled = true

    rule {
      status = "Enabled"

      transition {
        days          = 30
        storage_class = "STANDARD_IA"
      }

      expiration {
        days = 90
      }

      noncurrent_version_expiration {
        noncurrent_days = 90
      }
    }
  }
}

