  access_string = "my_access_string"
}

resource "aws_iam_policy" "elasticache_access" {
  name        = "elasticache-access-policy"
  description = "Policy to allow access to ElastiCache"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "elasticache:DescribeReplicationGroups",
          "elasticache:DescribeCacheClusters",
          "elasticache:DescribeCacheParameters",
          "elasticache:DescribeCacheSubnetGroups"
        ],
        Effect   = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_user_policy_attachment" "elasticache_attachment" {
  user       = aws_iam_user.example.name
  policy_arn = aws_iam_policy.elasticache_access.arn
}

