  description = "Debezium MSK Connect Plugin"
  location {
    s3 {
      bucket = "my-msk-connect-plugins-bucket"
      key    = "debezium.zip"
    }
  }
}

resource "aws_msk_connect_connector" "example" {
  name        = "debezium-connector"
  cluster_arn = aws_msk_cluster.example.arn
  plugins     = [{name = "debezium-plugin", configuration = jsonencode({"key.converter" : "org.apache.kafka.connect.storage.StringConverter"})}]
  capacity {
    auto_scaling {
      max_capacity = 3
      min_capacity = 1
    }
  }
}
```

