resource "aws_vpc" "autograde_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "autograde-vpc"
  }
}

resource "aws_subnet" "autograde_subnet" {
  vpc_id            = aws_vpc.autograde_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with desired AZ
  map_public_ip_on_launch = false # No public IP addresses

  tags = {
    Name = "autograde-subnet"
  }
}

resource "aws_internet_gateway" "autograde_igw" {
  vpc_id = aws_vpc.autograde_vpc.id

  tags = {
    Name = "autograde-igw"
  }
}

resource "aws_route_table" "autograde_route_table" {
  vpc_id = aws_vpc.autograde_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.autograde_igw.id
  }
}

resource "aws_route_table_association" "autograde_rta" {
  subnet_id      = aws_subnet.autograde_subnet.id
  route_table_id = aws_route_table.autograde_route_table.id
}

resource "aws_security_group" "autograde_sg" {
  name        = "autograde-sg"
  description = "Security group for CodeBuild"
  vpc_id      = aws_vpc.autograde_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_codebuild_project" "autograde_project" {
  name         = "autograde-project"
  description  = "CodeBuild project for autograding"
  service_role = "arn:aws:iam::YOUR_ACCOUNT_ID:role/CodeBuildServiceRole" # Replace with your CodeBuild service role

  source {
    type = "GITHUB"
    location = "YOUR_GITHUB_REPO_URL" # Replace with student's GitHub repo URL
    auth {
      type = "OAUTH"
    }
  }

  environment {
    type = "LINUX"
    image = "aws/codebuild/standard:7.0" # or the desired image.
    compute_type = "BUILD_GENERAL1_SMALL" # or other compute type
    privileged_mode = false
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs {
    cloudwatch_logs {
      group    = "/aws/codebuild/autograde-project"
      stream   = true
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.autograde_vpc.id
    subnets            = [aws_subnet.autograde_subnet.id]
    security_group_ids = [aws_security_group.autograde_sg.id]
  }
}

