    origin_id             = "S3VideoOrigin"
    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.id
    }
  }

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    forwarded_values {
      query_string = true
    }
    target_origin_id = "S3VideoOrigin"
    viewer_protocol_policy = "redirect-to-https"
  }

  price_class = "UseOnlyCloudFrontAccess"
  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_route53_record" "video_record" {
  zone_id = "YOUR_ROUTE53_ZONE_ID" # Replace with your Route 53 zone ID
  name    = "videos.example.com" # Replace with your desired domain name
  type    = "A"
  ttl     = "300"
  records = [
    aws_cloudfront_distribution.video_distribution.domain_name
  ]
}

resource "aws_s3_bucket_policy" "video_bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "GrantCloudFrontOriginAccessIdentityServicePrincipalReadOnly"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_origin_access_identity.oai.id}"
        }
        Action   = "s3:GetObject"
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}
