  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "aurora-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "subnet_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "aurora-subnet-1-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "aurora-subnet-2-${random_id.suffix.hex}"
  }
}

resource "aws_security_group" "rds_security_group" {
  name        = "rds-security-group-${random_id.suffix.hex}"
  description = "Allow inbound traffic to Aurora cluster"
  vpc_id      = aws_vpc.main.id
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_cluster" "aurora_cluster" {
  cluster_identifier      = "aurora-mysql-cluster-${random_id.suffix.hex}"
  engine                  = "aurora-mysql"
  engine_mode             = "serverless"
  engine_version          = "5.7.mysql_aurora.2.10.2"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = random_password.db.result
  vpc_security_group_ids = [aws_security_group.rds_security_group.id]
  db_subnet_group_name    = aws_db_subnet_group.default.name
  skip_final_snapshot     = true
}

resource "aws_db_subnet_group" "default" {
  name       = "aurora-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]
}

resource "aws_rds_proxy" "default" {
  proxy_identifier = "aurora-mysql-proxy-${random_id.suffix.hex}"
  engine_family    = "MYSQL"
  role_arns        = [aws_iam_role.rds_proxy_role.arn]
  vpc_subnet_ids   = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]
  auth_type        = "PASSWORD"
  secret_arn       = aws_secretsmanager_secret.db_credentials.arn
  idle_client_timeout = 1800
  enable_idle_client_timeout = true
  is_enabled = true
  require_ssl = false
  debug_logging = false
}
