  role_arn         = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:role/RDSProxyRole" # Replace with your actual IAM role ARN.
  vpc_subnet_ids   = [aws_subnet.public-subnet-a.id, aws_subnet.public-subnet-b.id]
  auth_type        = "PASSWORD"
  secret_arn       = aws_secretsmanager_secret.rds_secret.arn
}

